# ============================================\n# SCRIPT DE DIAGNÓSTICO - TV Connection\n# ============================================\n\nWrite-Host \"`n\" + \"=\"*60 -ForegroundColor Cyan\nWrite-Host \"🎥 DIAGNÓSTICO DE CONEXIÓN - SERVIDOR FLASK\" -ForegroundColor Cyan\nWrite-Host \"=\"*60 -ForegroundColor Cyan\n\n# ============================================\n# 1. INFORMACIÓN DEL SISTEMA\n# ============================================\nWrite-Host \"`n📋 1. INFORMACIÓN DEL SISTEMA\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$hostname = hostname\n$os = Get-CimInstance -ClassName Win32_OperatingSystem\n\nWrite-Host \"Nombre de máquina: $hostname\" -ForegroundColor White\nWrite-Host \"Sistema operativo: $($os.Caption)\" -ForegroundColor White\nWrite-Host \"Arquitectura: $(if ([System.Environment]::Is64BitOperatingSystem) { '64-bit' } else { '32-bit' })\" -ForegroundColor White\n\n# ============================================\n# 2. DIRECCIÓN IP\n# ============================================\nWrite-Host \"`n🌐 2. DIRECCIÓN IP DEL SERVIDOR\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$ips = Get-NetIPConfiguration | Where-Object { $_.IPv4DefaultGateway } | Select-Object -ExpandProperty IPv4Address | Select-Object -ExpandProperty IPAddress\n\nif ($ips) {\n    foreach ($ip in $ips) {\n        Write-Host \"✓ Dirección IP: $ip\" -ForegroundColor Green\n        Write-Host \"  URL para TV: http://$($ip):5000\" -ForegroundColor Green\n    }\n} else {\n    Write-Host \"✗ No se encontraron direcciones IP activas\" -ForegroundColor Red\n}\n\n# ============================================\n# 3. PUERTO 5000\n# ============================================\nWrite-Host \"`n🔌 3. ESTADO DEL PUERTO 5000\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$port5000 = netstat -ano -p TCP | findstr \":5000\"\n\nif ($port5000) {\n    Write-Host \"✓ Puerto 5000 está en uso:\" -ForegroundColor Green\n    Write-Host $port5000 -ForegroundColor Green\n    $pid = ($port5000 -split \"\\s+\")[-1]\n    $process = Get-Process -Id $pid -ErrorAction SilentlyContinue\n    if ($process) {\n        Write-Host \"✓ Proceso: $($process.Name) (PID: $pid)\" -ForegroundColor Green\n    }\n} else {\n    Write-Host \"✗ Puerto 5000 NO está en uso\" -ForegroundColor Red\n    Write-Host \"  → Asegúrate de ejecutar start_server.bat\" -ForegroundColor Yellow\n}\n\n# ============================================\n# 4. CONECTIVIDAD LOOPBACK\n# ============================================\nWrite-Host \"`n🔄 4. PRUEBA DE CONECTIVIDAD LOOPBACK\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$loopback = Test-Connection -ComputerName localhost -Count 1 -Quiet\nif ($loopback) {\n    Write-Host \"✓ Conexión localhost: OK\" -ForegroundColor Green\n} else {\n    Write-Host \"✗ Conexión localhost: FALLÓ\" -ForegroundColor Red\n}\n\n# ============================================\n# 5. CONECTIVIDAD RED LOCAL\n# ============================================\nWrite-Host \"`n📡 5. CONECTIVIDAD RED LOCAL\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$ipAddress = (Get-NetIPConfiguration | Where-Object { $_.IPv4DefaultGateway } | Select-Object -ExpandProperty IPv4Address | Select-Object -ExpandProperty IPAddress | Select-Object -First 1)\n\nif ($ipAddress) {\n    Write-Host \"Probando ping a: $ipAddress\" -ForegroundColor Cyan\n    $ping = Test-Connection -ComputerName $ipAddress -Count 1 -Quiet\n    if ($ping) {\n        Write-Host \"✓ Conexión de red local: OK\" -ForegroundColor Green\n    } else {\n        Write-Host \"✗ Conexión de red local: FALLÓ\" -ForegroundColor Red\n    }\n} else {\n    Write-Host \"✗ No se puede obtener dirección IP\" -ForegroundColor Red\n}\n\n# ============================================\n# 6. FIREWALL\n# ============================================\nWrite-Host \"`n🛡️  6. ESTADO DEL FIREWALL\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$firewall = Get-NetFirewallProfile | Select-Object -First 1\nif ($firewall.Enabled) {\n    Write-Host \"✓ Firewall está ACTIVO\" -ForegroundColor Yellow\n    Write-Host \"  → Verifica que Python en puerto 5000 esté permitido\" -ForegroundColor Yellow\n} else {\n    Write-Host \"✓ Firewall está DESACTIVO\" -ForegroundColor Green\n}\n\n# ============================================\n# 7. PYTHON Y FLASK\n# ============================================\nWrite-Host \"`n🐍 7. VERIFICACIÓN DE PYTHON Y FLASK\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$python = Get-Command python -ErrorAction SilentlyContinue\nif ($python) {\n    Write-Host \"✓ Python instalado en: $($python.Source)\" -ForegroundColor Green\n    $pythonVersion = & python --version\n    Write-Host \"  Versión: $pythonVersion\" -ForegroundColor Green\n    \n    # Verificar Flask\n    $flask = & python -c \"import flask; print(flask.__version__)\" 2>$null\n    if ($LASTEXITCODE -eq 0) {\n        Write-Host \"✓ Flask instalado (versión: $flask)\" -ForegroundColor Green\n    } else {\n        Write-Host \"✗ Flask NO está instalado\" -ForegroundColor Red\n        Write-Host \"  → Ejecuta: pip install flask\" -ForegroundColor Yellow\n    }\n} else {\n    Write-Host \"✗ Python NO está instalado\" -ForegroundColor Red\n}\n\n# ============================================\n# 8. ARCHIVOS NECESARIOS\n# ============================================\nWrite-Host \"`n📁 8. ARCHIVOS NECESARIOS\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\n$basePath = \"C:\\Users\\admin\\Server\\FlaskApp\"\n$requiredFiles = @(\n    \"app.py\",\n    \"start_server.bat\",\n    \"templates\\slideshow.html\",\n    \"static\\css\\slideshow.css\",\n    \"static\\js\\slideshow.js\"\n)\n\nforeach ($file in $requiredFiles) {\n    $fullPath = Join-Path $basePath $file\n    if (Test-Path $fullPath) {\n        Write-Host \"✓ $file\" -ForegroundColor Green\n    } else {\n        Write-Host \"✗ $file NO ENCONTRADO\" -ForegroundColor Red\n    }\n}\n\n# ============================================\n# 9. RESUMEN Y RECOMENDACIONES\n# ============================================\nWrite-Host \"`n🎯 RESUMEN Y RECOMENDACIONES\" -ForegroundColor Yellow\nWrite-Host \"-\" * 60\n\nif ($port5000) {\n    Write-Host \"`n✅ El servidor parece estar corriendo correctamente.\" -ForegroundColor Green\n    Write-Host \"`nIntenta acceder desde la TV con:\" -ForegroundColor Green\n    Write-Host \"   http://$($ipAddress):5000\" -ForegroundColor Cyan\n    Write-Host \"`nSi aún no funciona, verifica:\" -ForegroundColor Yellow\n    Write-Host \"  1. La TV está en la misma red WiFi\" -ForegroundColor Yellow\n    Write-Host \"  2. La TV puede acceder a esta IP (ping 192.168.178.188)\" -ForegroundColor Yellow\n    Write-Host \"  3. El navegador de la TV tiene soporte JavaScript\" -ForegroundColor Yellow\n} else {\n    Write-Host \"`n⚠️  El servidor NO está corriendo.\" -ForegroundColor Yellow\n    Write-Host \"`nPara iniciarlo:\" -ForegroundColor Yellow\n    Write-Host \"  1. Abre PowerShell como administrador\" -ForegroundColor Yellow\n    Write-Host \"  2. Ve a: cd C:\\Users\\admin\\Server\\FlaskApp\" -ForegroundColor Yellow\n    Write-Host \"  3. Ejecuta: start_server.bat\" -ForegroundColor Yellow\n}\n\nWrite-Host \"`n\" + \"=\"*60 -ForegroundColor Cyan\nWrite-Host \"Presiona Enter para cerrar...\" -ForegroundColor Cyan\nRead-Host\n"